CREATE TABLE multi_sided_market_participant_profile (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, participant_id VARCHAR(160) NOT NULL, roles TEXT NOT NULL, verification_level VARCHAR(80) NOT NULL, trust_score DECIMAL(12,4) NOT NULL, default_currency VARCHAR(12) NOT NULL, policy_context TEXT, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_marketplace_listing (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, listing_id VARCHAR(160) NOT NULL, participant_id VARCHAR(160) NOT NULL, title VARCHAR(240) NOT NULL, kind VARCHAR(80) NOT NULL, exchange_modes TEXT NOT NULL, price DECIMAL(18,4), currency VARCHAR(12), published_at TIMESTAMP, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_listing_asset (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, asset_id VARCHAR(160) NOT NULL, listing_id VARCHAR(160) NOT NULL, asset_type VARCHAR(80) NOT NULL, quantity DECIMAL(18,4) NOT NULL, condition_grade VARCHAR(80), location TEXT, attributes TEXT, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_service_offer (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, offer_id VARCHAR(160) NOT NULL, listing_id VARCHAR(160) NOT NULL, provider_id VARCHAR(160) NOT NULL, service_type VARCHAR(120) NOT NULL, duration_minutes INTEGER NOT NULL, service_area TEXT, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_availability_window (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, window_id VARCHAR(160) NOT NULL, listing_id VARCHAR(160) NOT NULL, starts_at TIMESTAMP NOT NULL, ends_at TIMESTAMP NOT NULL, capacity INTEGER NOT NULL, reserved_count INTEGER NOT NULL, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_booking_reservation (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, booking_id VARCHAR(160) NOT NULL, listing_id VARCHAR(160) NOT NULL, participant_id VARCHAR(160) NOT NULL, starts_at TIMESTAMP NOT NULL, ends_at TIMESTAMP NOT NULL, hold_expires_at TIMESTAMP, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_rental_contract (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, rental_id VARCHAR(160) NOT NULL, listing_id VARCHAR(160) NOT NULL, renter_id VARCHAR(160) NOT NULL, condition_out TEXT NOT NULL, condition_in TEXT, collateral_amount DECIMAL(18,4) NOT NULL, return_due_at TIMESTAMP, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_loan_agreement (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, loan_id VARCHAR(160) NOT NULL, listing_id VARCHAR(160) NOT NULL, borrower_id VARCHAR(160) NOT NULL, return_due_at TIMESTAMP NOT NULL, collateral_rate DECIMAL(12,4) NOT NULL, risk_score DECIMAL(12,4), status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_barter_offer (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, offer_id VARCHAR(160) NOT NULL, listing_id VARCHAR(160) NOT NULL, offered_listing_id VARCHAR(160) NOT NULL, requested_value DECIMAL(18,4) NOT NULL, offered_value DECIMAL(18,4) NOT NULL, valuation_delta DECIMAL(18,4) NOT NULL, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_trade_order (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, order_id VARCHAR(160) NOT NULL, listing_id VARCHAR(160) NOT NULL, offered_listing_id VARCHAR(160) NOT NULL, quantity DECIMAL(18,4) NOT NULL, clearing_score DECIMAL(12,4), status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_sale_order (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, sale_id VARCHAR(160) NOT NULL, listing_id VARCHAR(160) NOT NULL, buyer_id VARCHAR(160) NOT NULL, amount DECIMAL(18,4) NOT NULL, currency VARCHAR(12) NOT NULL, payment_reference VARCHAR(200), status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_exchange_proposal (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, proposal_id VARCHAR(160) NOT NULL, source_listing_id VARCHAR(160) NOT NULL, target_listing_id VARCHAR(160) NOT NULL, exchange_mode VARCHAR(80) NOT NULL, score DECIMAL(12,4) NOT NULL, explanation TEXT, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_escrow_account (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, escrow_id VARCHAR(160) NOT NULL, exchange_id VARCHAR(160) NOT NULL, amount DECIMAL(18,4) NOT NULL, currency VARCHAR(12) NOT NULL, hold_until TIMESTAMP, release_policy_hash VARCHAR(200) NOT NULL, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_settlement_instruction (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, settlement_id VARCHAR(160) NOT NULL, exchange_id VARCHAR(160) NOT NULL, amount DECIMAL(18,4) NOT NULL, currency VARCHAR(12) NOT NULL, destination_account VARCHAR(240) NOT NULL, settlement_policy TEXT, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_dispute_case (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, dispute_id VARCHAR(160) NOT NULL, exchange_id VARCHAR(160) NOT NULL, reason VARCHAR(240) NOT NULL, triage VARCHAR(120) NOT NULL, evidence TEXT, resolution TEXT, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_reputation_signal (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, signal_id VARCHAR(160) NOT NULL, participant_id VARCHAR(160) NOT NULL, source_exchange_id VARCHAR(160) NOT NULL, score_delta DECIMAL(12,4) NOT NULL, reason VARCHAR(240) NOT NULL, proof_hash VARCHAR(200), status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_market_rule (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, rule_id VARCHAR(160) NOT NULL, rule_type VARCHAR(120) NOT NULL, policy_body TEXT NOT NULL, compiled_hash VARCHAR(200) NOT NULL, effective_from TIMESTAMP, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_market_parameter (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, parameter_id VARCHAR(160) NOT NULL, name VARCHAR(160) NOT NULL, value TEXT NOT NULL, bounds TEXT, changed_by VARCHAR(160), status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_schema_extension (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, extension_id VARCHAR(160) NOT NULL, table_name VARCHAR(160) NOT NULL, fields TEXT NOT NULL, schema_version INTEGER NOT NULL, compatibility VARCHAR(80) NOT NULL, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_governed_model (id INTEGER PRIMARY KEY, tenant VARCHAR(120) NOT NULL, model_id VARCHAR(160) NOT NULL, name VARCHAR(160) NOT NULL, purpose VARCHAR(240) NOT NULL, model_version VARCHAR(80) NOT NULL, metrics TEXT, governance_status VARCHAR(80) NOT NULL, status VARCHAR(40) NOT NULL, version INTEGER NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_appgen_outbox_event (id INTEGER PRIMARY KEY, event_type VARCHAR(120) NOT NULL, payload TEXT NOT NULL, idempotency_key VARCHAR(200) NOT NULL, published_at TIMESTAMP, created_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_appgen_inbox_event (id INTEGER PRIMARY KEY, event_type VARCHAR(120) NOT NULL, payload TEXT NOT NULL, idempotency_key VARCHAR(200) NOT NULL, consumed_at TIMESTAMP, created_at TIMESTAMP NOT NULL);
CREATE TABLE multi_sided_market_appgen_dead_letter_event (id INTEGER PRIMARY KEY, event_type VARCHAR(120) NOT NULL, payload TEXT NOT NULL, idempotency_key VARCHAR(200), retry_count INTEGER NOT NULL, failure_reason TEXT, created_at TIMESTAMP NOT NULL);
